// Input Normalizer — validates and normalizes all inputs
const input = $json;
const operation = input.operation || 'search';

const DOC_TYPE_MAP = {
  'Rechnung': 'Invoice',
  'Kontoauszug': 'BankStatement',
  'Dokument': 'Document',
  'Email': 'Email',
  'WertpapierAbrechnung': 'SecuritySettlement',
  'Vertrag': 'Contract'
};

const ALL_COLLECTIONS = ['Invoice', 'BankStatement', 'Document', 'Email', 'SecuritySettlement', 'Contract'];

// Determine which collections to search
let collections = ALL_COLLECTIONS;
if (operation === 'search') {
  const docType = input.doc_type;
  if (docType && docType !== 'alle' && DOC_TYPE_MAP[docType]) {
    collections = [DOC_TYPE_MAP[docType]];
  }
}

// Normalize limit (1–20, default 5)
let limit = parseInt(input.limit) || 5;
if (limit > 20) limit = 20;
if (limit < 1) limit = 1;

// Normalize dates — swap if inverted
let dateFrom = input.date_from || null;
let dateTo = input.date_to || null;
if (dateFrom && dateTo && dateFrom > dateTo) {
  const tmp = dateFrom;
  dateFrom = dateTo;
  dateTo = tmp;
}

return [{ json: {
  operation,
  userId: input.user_id || null,
  query: input.query || '',
  collections,
  dateFrom,
  dateTo,
  limit,
  weaviateId: input.weaviate_id || null,
  collection: input.collection || null
}}];

// Apply DMS Permission Filter — restrict collections to those the user has can_read=TRUE
const inputData = $('Input Normalizer').first().json;
const permRows = $input.all().map(item => item.json);

// If no user_id was provided or permission query failed, deny all access
if (!inputData.userId || permRows.length === 0) {
  if (inputData.operation === 'search') {
    return [{ json: { ...inputData, collections: [] } }];
  }
  // For details: check if the requested collection is allowed
  return [{ json: { ...inputData, allowedCollections: [] } }];
}

// Build list of allowed collection names from permission rows
const allowedDocTypes = permRows.map(r => r.doc_type);

// Wildcard '*' means all collections are allowed
const ALL_COLLECTIONS = ['Invoice', 'BankStatement', 'Document', 'Email', 'SecuritySettlement', 'Contract'];
const hasWildcard = allowedDocTypes.includes('*');
const allowedCollections = hasWildcard ? ALL_COLLECTIONS : allowedDocTypes.filter(t => ALL_COLLECTIONS.includes(t));

if (inputData.operation === 'search') {
  // Filter requested collections to only allowed ones
  const filteredCollections = inputData.collections.filter(c => allowedCollections.includes(c));
  return [{ json: { ...inputData, collections: filteredCollections } }];
} else {
  // For details: pass allowed collections so the details node can check
  return [{ json: { ...inputData, allowedCollections } }];
}

// Weaviate nearText search across selected collections using axios
const { query, collections, dateFrom, dateTo, limit } = $json;

// If no collections allowed (permission denied), return empty results
if (!collections || collections.length === 0) {
  return [{ json: { results: [], error: null } }];
}

const WEAVIATE_URL = 'http://weaviate:8080';

const DATE_FIELDS = {
  Invoice: 'invoiceDate',
  BankStatement: 'statementDate',
  Contract: 'startDate',
  Email: 'date',
  SecuritySettlement: 'transactionDate',
  Document: 'documentDate'
};

const KEY_FIELDS_MAP = {
  Invoice: ['issuer', 'recipient', 'category'],
  BankStatement: ['bankName', 'accountHolder', 'iban'],
  Document: ['sender', 'recipient', 'category'],
  Email: ['sender', 'senderName', 'subject', 'recipients'],
  SecuritySettlement: ['securityName', 'transactionType', 'isin'],
  Contract: ['contractPartner', 'contractType', 'monthlyCost']
};

const AMOUNT_FIELDS = {
  Invoice: 'amountGross',
  BankStatement: 'closingBalance',
  SecuritySettlement: 'settlementAmount'
};

function buildGraphQL(collection) {
  const dateField = DATE_FIELDS[collection];
  const keyFields = KEY_FIELDS_MAP[collection] || [];
  const amountField = AMOUNT_FIELDS[collection];

  // Build optional where clause for date range
  let whereClause = '';
  if (dateFrom || dateTo) {
    const conds = [];
    if (dateFrom) conds.push(`{ path: ["${dateField}"], operator: GreaterThanEqual, valueDate: "${dateFrom}T00:00:00Z" }`);
    if (dateTo)   conds.push(`{ path: ["${dateField}"], operator: LessThanEqual,    valueDate: "${dateTo}T23:59:59Z" }`);
    whereClause = conds.length === 1
      ? `where: ${conds[0]}`
      : `where: { operator: And, operands: [${conds.join(', ')}] }`;
  }

  const allFields = ['_additional { id distance }', 'summary', dateField, ...keyFields];
  if (amountField) allFields.push(amountField);

  const escapedQuery = query.replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\n/g, ' ').replace(/\r/g, ' ').replace(/\t/g, ' ').replace(/[\x00-\x1f]/g, '');

  return {
    query: `{ Get { ${collection}(nearText: { concepts: ["${escapedQuery}"], distance: 0.8 } ${whereClause} limit: ${limit}) { ${allFields.join(' ')} } } }`
  };
}

try {
  const axios = require('axios');

  const requests = collections.map(col =>
    axios.post(`${WEAVIATE_URL}/v1/graphql`, buildGraphQL(col), {
      headers: { 'Content-Type': 'application/json' },
      timeout: 10000
    })
    .then(res => ({ collection: col, data: res.data }))
    .catch(err => ({ collection: col, error: err.message, data: null }))
  );

  const responses = await Promise.all(requests);

  const results = [];
  for (const resp of responses) {
    if (!resp.data || resp.error) continue;
    const collData = resp.data?.data?.Get?.[resp.collection] || [];
    const dateField = DATE_FIELDS[resp.collection];
    const amountField = AMOUNT_FIELDS[resp.collection];

    for (const item of collData) {
      const distance = item._additional?.distance ?? 1.0;
      if (distance > 0.8) continue;

      const key_fields = {};
      for (const f of KEY_FIELDS_MAP[resp.collection] || []) {
        if (item[f] != null) key_fields[f] = item[f];
      }

      const result = {
        weaviate_id: item._additional?.id,
        collection: resp.collection,
        score: distance,
        title_or_summary: item.summary || '',
        date: item[dateField] || null,
        key_fields
      };
      if (amountField && item[amountField] != null) {
        result.amount = item[amountField];
      }
      results.push(result);
    }
  }

  // Sort ascending by score (lower distance = better match)
  results.sort((a, b) => a.score - b.score);
  const limited = results.slice(0, limit);

  return [{ json: { results: limited, error: null } }];
} catch (err) {
  return [{ json: { results: [], error: err.message } }];
}

// Weaviate GET single document by UUID and collection
const { weaviateId, collection, allowedCollections } = $json;
const WEAVIATE_URL = 'http://weaviate:8080';

if (!weaviateId || !collection) {
  return [{ json: { document: {}, error: 'Missing weaviate_id or collection' } }];
}

// Check if user has permission to read this collection
if (!allowedCollections || !allowedCollections.includes(collection)) {
  return [{ json: { document: {}, error: 'Keine Berechtigung für diesen Dokumenttyp' } }];
}

try {
  const axios = require('axios');
  const resp = await axios.get(
    `${WEAVIATE_URL}/v1/objects/${collection}/${weaviateId}`,
    { timeout: 10000 }
  );
  return [{ json: { document: resp.data, error: null } }];
} catch (err) {
  if (err.response?.status === 404) {
    return [{ json: { document: {}, error: 'Dokument nicht gefunden' } }];
  }
  return [{ json: { document: {}, error: err.message } }];
}
